import { Box, Button, Container, FormControlLabel, Grid, makeStyles, Paper, Radio, TextField, Typography } from '@material-ui/core';
import { AddRounded, CheckBox } from '@material-ui/icons';
import React from 'react';

const useStyle = makeStyles(theme => {
  return {
    paper: {
      padding: theme.spacing(2),
      borderTop: '10px solid #162276'
    },
    quizPaper: {
      padding: theme.spacing(2),
      borderLeft: '10px solid #162276'
    }
  }
})

const CreateQuiz = () => {
  const classes = useStyle()


  return (
    <Container>
      <Box mb={2}>
        Create Quiz
        <Paper className={classes.paper}>
          <TextField placeholder='Quiz title'  fullWidth/>
          <TextField placeholder='Description' fullWidth/>
        </Paper>
      </Box>
      <Box mb={2}>
        <Paper className={classes.paper}>
          <TextField placeholder='Question'  fullWidth/>
          <TextField placeholder='Description' fullWidth/>
        </Paper>
      </Box>
    </Container>
  );
}

export default CreateQuiz;
